class Solution:
    def maxSubarraySum(self, nums, k):
        # independent re-derivation: direct double loop over every subarray,
        # correct but only intended for small inputs
        n = len(nums)
        best = None
        for i in range(n):
            s = 0
            for j in range(i, n):
                s += nums[j]
                length = j - i + 1
                if length % k == 0:
                    if best is None or s > best:
                        best = s
        return best

