class Solution:
    def maxSubarraySum(self, nums, k):
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        INF = float('inf')
        min_at_rem = [INF] * k
        min_at_rem[0] = prefix[0]
        best = float('-inf')
        for i in range(1, n + 1):
            r = i % k
            if min_at_rem[r] < INF:
                best = max(best, prefix[i] - min_at_rem[r])
            if prefix[i] < min_at_rem[r]:
                min_at_rem[r] = prefix[i]
        return best

