var maxSubarraySum = function(nums, k) {
    const n = nums.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + nums[i];
    const minAt = new Array(k).fill(Infinity);
    minAt[0] = prefix[0];
    let best = -Infinity;
    for (let i = 1; i <= n; i++) {
        const r = i % k;
        if (minAt[r] < Infinity) best = Math.max(best, prefix[i] - minAt[r]);
        if (prefix[i] < minAt[r]) minAt[r] = prefix[i];
    }
    return best;
};
